class Solution:
    def oddCells(self, m: int, n: int, indices) -> int:
        grid = [[0]*n for _ in range(m)]
        for r, c in indices:
            for j in range(n):
                grid[r][j] += 1
            for i in range(m):
                grid[i][c] += 1
        return sum(1 for i in range(m) for j in range(n) if grid[i][j] % 2 == 1)

